<template><view class="page"><view class="hero"><text class="eyebrow">COMMERCIAL OPS</text><text class="title">商业运营</text><text class="desc">管理套餐、订单、权益和异常任务。</text></view><view class="tabs"><text v-for="(t,i) in tabs" :key="t" :class="tab===i?'active':''" @click="tab=i">{{t}}</text></view>
<template v-if="tab===0"><button class="primary" @click="editing={code:'',name:'',description:'',price:0,entitlement_type:'name_generate',entitlement_amount:10,is_active:true,sort_order:0}">新增套餐</button><view v-for="p in products" :key="p.id" class="card"><view class="row"><text class="name">{{p.name}}</text><text :class="p.is_active?'ok':'muted'">{{p.is_active?'上架':'下架'}}</text></view><text class="meta">¥{{p.price}} · {{p.entitlement_amount}} {{p.entitlement_type}}</text><view class="actions"><text @click="editing={...p}">编辑</text><text @click="toggleProduct(p)">{{p.is_active?'下架':'上架'}}</text></view></view></template>
<template v-if="tab===1"><button class="primary" @click="closeExpired">关闭过期订单</button><view v-for="o in orders" :key="o.id" class="card"><view class="row"><text class="name">{{o.order_no}}</text><text>{{statusText(o.pay_status)}}</text></view><text class="meta">用户 #{{o.user_id}} · ¥{{o.amount}} · {{date(o.created_at)}}</text></view></template>
<template v-if="tab===2"><view class="stats"><view><text>{{stats.payment_failures?.total||0}}</text><text>支付失败</text></view><view><text>{{stats.report_failures?.total||0}}</text><text>报告失败</text></view><view><text>{{stats.visual_generation_failures?.total||0}}</text><text>视觉失败</text></view></view><view class="card"><text class="name">手动调整权益</text><input v-model="adjust.user_id" type="number" placeholder="用户 ID"/><picker :range="entitlementLabels" @change="adjustType=Number($event.detail.value)"><view class="picker">{{entitlementLabels[adjustType]}}⌄</view></picker><input v-model="adjust.change_amount" type="number" placeholder="变更数量，可填负数"/><input v-model="adjust.remark" placeholder="调整原因"/><button class="primary" @click="submitAdjust">确认调整</button></view><view class="card"><text class="name">任务规模</text><text class="meta">报告任务 {{reportTotal}} · 视觉任务 {{visualTotal}}</text></view></template>
<view v-if="editing" class="mask" @click.self="editing=null"><view class="dialog"><text class="name">{{editing.id?'编辑套餐':'新增套餐'}}</text><input v-model="editing.code" placeholder="套餐编码"/><input v-model="editing.name" placeholder="套餐名称"/><input v-model="editing.description" placeholder="套餐说明"/><input v-model="editing.price" type="digit" placeholder="价格"/><picker :range="entitlementLabels" @change="editing.entitlement_type=entitlementTypes[$event.detail.value]"><view class="picker">{{editing.entitlement_type}}</view></picker><input v-model="editing.entitlement_amount" type="number" placeholder="权益数量"/><button class="primary" @click="saveProduct">保存</button><button @click="editing=null">取消</button></view></view></view></template>
<script setup>import{ref}from'vue';import{onPullDownRefresh,onShow}from'@dcloudio/uni-app';import http from'@/http/http.js';const tabs=['商品','订单','运营'],tab=ref(0),products=ref([]),orders=ref([]),stats=ref({}),editing=ref(null),reportTotal=ref(0),visualTotal=ref(0);const entitlementTypes=['name_generate','report_generate','visual_generate'],entitlementLabels=['起名次数','报告权益','视觉权益'],adjustType=ref(0),adjust=ref({user_id:'',change_amount:'',remark:''});const load=async()=>{try{const[p,o,s,r,v]=await Promise.all([http.getAdminProducts({page:1,page_size:100}),http.getAdminOrders({page:1,page_size:100}),http.getAdminCommercialStats(),http.getAdminReports({page:1,page_size:1}),http.getAdminVisuals({page:1,page_size:1})]);products.value=p.items||[];orders.value=o.items||[];stats.value=s||{};reportTotal.value=r.total||0;visualTotal.value=v.total||0;}finally{uni.stopPullDownRefresh();}};onShow(load);onPullDownRefresh(load);const toggleProduct=async p=>{await http.setAdminProductStatus(p.id,!p.is_active);await load();};const saveProduct=async()=>{const e=editing.value,data={code:e.code,name:e.name,description:e.description||null,price:Number(e.price),entitlement_type:e.entitlement_type,entitlement_amount:Number(e.entitlement_amount),is_active:e.is_active!==false,sort_order:Number(e.sort_order||0)};e.id?await http.updateAdminProduct(e.id,data):await http.createAdminProduct(data);editing.value=null;await load();};const closeExpired=async()=>{const r=await http.closeExpiredOrders();uni.showToast({title:`已关闭 ${r.count||0} 笔`,icon:'none'});await load();};const submitAdjust=async()=>{await http.adjustEntitlement({user_id:Number(adjust.value.user_id),entitlement_type:entitlementTypes[adjustType.value],change_amount:Number(adjust.value.change_amount),remark:adjust.value.remark||null});adjust.value={user_id:'',change_amount:'',remark:''};uni.showToast({title:'权益调整成功',icon:'success'});};const statusText=v=>({pending:'待支付',paid:'已支付',failed:'失败',closed:'已关闭'}[v]||v);const date=v=>String(v||'').replace('T',' ').slice(0,16);</script>
<style scoped>.page{min-height:100vh;padding:30rpx;box-sizing:border-box;background:#f7f4ee;color:#292620}.hero{padding:30rpx;color:#fff;border-radius:24rpx;background:#344d41}.eyebrow,.title,.desc,.meta,.name{display:block}.eyebrow{font-size:16rpx;letter-spacing:3rpx}.title{margin-top:7rpx;font-size:38rpx;font-weight:700}.desc{margin-top:8rpx;opacity:.72;font-size:20rpx}.tabs{display:flex;margin:22rpx 0;border-radius:14rpx;background:#fff}.tabs text{flex:1;padding:20rpx;text-align:center;color:#8e8579}.tabs .active{color:#355446;font-weight:700;border-bottom:4rpx solid #496b5b}.card{margin-top:15rpx;padding:24rpx;border-radius:18rpx;background:#fff}.row{display:flex;justify-content:space-between}.name{font-size:25rpx;font-weight:700}.meta{margin-top:8rpx;color:#958c80;font-size:19rpx}.ok{color:#347050}.muted{color:#999}.actions{text-align:right;margin-top:15rpx}.actions text{margin-left:24rpx;color:#4c6c5d}.primary{margin:15rpx 0;color:#fff;background:#3e5a4d}.stats{display:flex;gap:12rpx}.stats view{flex:1;padding:22rpx 5rpx;border-radius:15rpx;background:#fff;text-align:center}.stats text{display:block}.stats text:first-child{font-size:31rpx;font-weight:700}.stats text:last-child{font-size:17rpx;color:#91887d}.card input,.picker{height:72rpx;margin-top:14rpx;padding:0 18rpx;line-height:72rpx;border-radius:10rpx;background:#f6f3ed}.mask{position:fixed;inset:0;z-index:9;display:flex;align-items:center;justify-content:center;padding:30rpx;background:rgba(0,0,0,.42)}.dialog{width:100%;max-height:85vh;overflow:auto;padding:28rpx;border-radius:20rpx;background:#fff}</style>
